import React, { useEffect, useState } from 'react';
import axios from 'axios';

export default function StudentFees() {
  const [fees, setFees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedFee, setSelectedFee] = useState(null);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    axios.get('/fees/my').then(r => setFees(r.data)).catch(console.error).finally(() => setLoading(false));
  }, []);

  const filtered = filter === 'all' ? fees : fees.filter(f => f.status === filter);
  const fmt = (n) => `₹${Number(n || 0).toLocaleString('en-IN')}`;

  if (loading) return <div className="loading-screen" style={{ height: 300 }}><div className="spinner" /></div>;

  return (
    <div>
      <div className="search-bar">
        {['all', 'pending', 'paid', 'overdue'].map(s => (
          <button key={s} className={`btn ${filter === s ? 'btn-primary' : 'btn-outline'}`} onClick={() => setFilter(s)} style={{ textTransform: 'capitalize' }}>
            {s === 'all' ? '📋 All' : s === 'paid' ? '✅ Paid' : s === 'pending' ? '⏳ Pending' : '⚠️ Overdue'} ({s === 'all' ? fees.length : fees.filter(f => f.status === s).length})
          </button>
        ))}
      </div>

      <div className="card">
        <div className="card-header"><h3 className="card-title">My Fee Records</h3></div>
        {filtered.length === 0 ? (
          <div className="empty-state"><span className="icon">📭</span><p>No {filter} records found</p></div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead><tr><th>Month</th><th>Route</th><th>Amount</th><th>Late Fee</th><th>Discount</th><th>Total</th><th>Due Date</th><th>Status</th><th>Receipt</th></tr></thead>
              <tbody>
                {filtered.map(f => (
                  <tr key={f.id}>
                    <td><strong>{f.feeMonth}</strong></td>
                    <td style={{ fontSize: 12 }}>{f.route?.routeNumber} - {f.route?.routeName}</td>
                    <td>{fmt(f.amount)}</td>
                    <td style={{ color: f.lateFee > 0 ? 'var(--danger)' : 'inherit' }}>{f.lateFee > 0 ? fmt(f.lateFee) : '—'}</td>
                    <td style={{ color: f.discount > 0 ? 'var(--success)' : 'inherit' }}>{f.discount > 0 ? `-${fmt(f.discount)}` : '—'}</td>
                    <td><strong>{fmt(f.totalAmount)}</strong></td>
                    <td style={{ fontSize: 12, color: new Date(f.dueDate) < new Date() && f.status === 'pending' ? 'var(--danger)' : 'inherit' }}>{f.dueDate}</td>
                    <td><span className={`badge badge-${f.status}`}>{f.status}</span></td>
                    <td>
                      {f.status === 'paid' && f.receiptNumber ? (
                        <button className="btn btn-outline btn-sm" onClick={() => setSelectedFee(f)}>🧾</button>
                      ) : '—'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {selectedFee && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setSelectedFee(null)}>
          <div className="modal" style={{ maxWidth: 380 }}>
            <div className="modal-header"><h3 className="modal-title">🧾 Payment Receipt</h3><button className="modal-close" onClick={() => setSelectedFee(null)}>×</button></div>
            <div className="receipt">
              <div className="receipt-header">
                <div style={{ fontSize: 28 }}>🚌</div>
                <div style={{ fontWeight: 800, fontSize: 16 }}>Campus Bus Services</div>
                <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>Official Fee Receipt</div>
              </div>
              <div className="receipt-row"><span>Receipt No:</span><strong style={{ color: 'var(--primary)' }}>{selectedFee.receiptNumber}</strong></div>
              <div className="receipt-row"><span>Fee Month:</span><strong>{selectedFee.feeMonth}</strong></div>
              <div className="receipt-row"><span>Route:</span><span>{selectedFee.route?.routeNumber} - {selectedFee.route?.routeName}</span></div>
              <div className="receipt-row"><span>Base Amount:</span><span>{fmt(selectedFee.amount)}</span></div>
              {selectedFee.lateFee > 0 && <div className="receipt-row"><span>Late Fee:</span><span style={{ color: 'var(--danger)' }}>+{fmt(selectedFee.lateFee)}</span></div>}
              {selectedFee.discount > 0 && <div className="receipt-row"><span>Discount:</span><span style={{ color: 'var(--success)' }}>-{fmt(selectedFee.discount)}</span></div>}
              <div className="receipt-total"><span>Total Paid:</span><strong style={{ color: 'var(--success)', fontSize: 18 }}>{fmt(selectedFee.totalAmount)}</strong></div>
              <div className="receipt-row"><span>Payment Mode:</span><span style={{ textTransform: 'capitalize' }}>{selectedFee.paymentMode}</span></div>
              {selectedFee.transactionId && <div className="receipt-row"><span>Transaction ID:</span><span>{selectedFee.transactionId}</span></div>}
              <div className="receipt-row"><span>Paid On:</span><span>{selectedFee.paidDate}</span></div>
              <div style={{ textAlign: 'center', marginTop: 16, fontSize: 12, color: 'var(--text-muted)' }}>✅ Payment Verified</div>
            </div>
            <button className="btn btn-outline" style={{ width: '100%', marginTop: 10, justifyContent: 'center' }} onClick={() => window.print()}>🖨️ Print</button>
          </div>
        </div>
      )}
    </div>
  );
}
